// ── Accordion Item ────────────────────────────────────────────────────────────
function Accordion({ q, a }: { q: string; a: string }) {
  const [open, setOpen] = useState(false);
  return (
    <div
      className="border-b border-border/40 last:border-0"
      onClick={() => setOpen(o => !o)}
    >
      <button className="w-full flex items-center justify-between py-4 text-left gap-4">
        <span className="font-medium text-sm" style={{ fontFamily: "'Lato', sans-serif" }}>{q}</span>
        {open
          ? <ChevronUp className="w-4 h-4 text-muted-foreground shrink-0" />
          : <ChevronDown className="w-4 h-4 text-muted-foreground shrink-0" />}
      </button>
      {open && (
        <p className="text-sm text-muted-foreground leading-relaxed pb-4" style={{ fontFamily: "'Lora', serif", lineHeight: 1.75 }}>
          {a}
        </p>
      )}
    </div>
  );
}

